import ComponentBase from "./ComponentBase";


const { ccclass, property } = cc._decorator;

@ccclass
export class SpriteFrameComponent extends ComponentBase {

    @property({ type: [cc.SpriteFrame] })
    public spriteFrameList: Array<cc.SpriteFrame> = []


    @property({ type: [cc.Font] })
    public fontList: Array<cc.Font> = []

    @property({ type: [sp.SkeletonData] })
    public spineList: Array<sp.SkeletonData> = []

}