import BasePlatformAPI from "./BasePlatformAPI";

export default class ShareAPI extends BasePlatformAPI {

    private static share : ShareAPI = null;
    public static get Init() : ShareAPI{
        if(this.share == null){
            this.share = new ShareAPI();
        }
        return this.share;
    }

    /**显示当前页面的转发按钮 
    * @param withShareTicket 是否使用带 shareTicket 的转发
    */
    ShowShareMenu(withShareTicket = false){
        if(!this.api) return;
        this.api.showShareMenu(
            {
                withShareTicket:withShareTicket
            }
        )
    }

    /**隐藏转发按钮 */
    HideShareMenu(){
        if(!this.api) return;
        this.api.hideShareMenu()
    }

    /**监听用户点击右上角菜单的「转发」按钮时触发的事件
     * @param title   转发标题，不传则默认使用当前小游戏的昵称。
     * @param imageurl 转发显示图片的链接，可以是网络图片路径或本地图片文件路径或相对代码包根目录的图片文件路径。显示图片长宽比是 5:4
     * @param query 查询字符串，必须是 key1=val1&key2=val2 的格式。从这条转发消息进入后，可通过 wx.getLaunchOptionSync() 或 wx.onShow() 获取启动参数中的 query。
     * @param imageurlid 审核通过的图片 ID
     */
    public OnShareAppMessage(_handle : Function){
        if(!this.api) {
            _handle && _handle(null);
            return;
        }
        this.api.onShareAppMessage(_handle);
    }

    /**主动拉起转发，进入选择通讯录界面。
     * @param title   转发标题，不传则默认使用当前小游戏的昵称。
     * @param imageurl 转发显示图片的链接，可以是网络图片路径或本地图片文件路径或相对代码包根目录的图片文件路径。显示图片长宽比是 5:4
     * @param query 查询字符串，必须是 key1=val1&key2=val2 的格式。从这条转发消息进入后，可通过 wx.getLaunchOptionSync() 或 wx.onShow() 获取启动参数中的 query。
     */
     public ShareAppMessage(title : string , imageurl : string , query : string|null){
        if(!this.api) return;
        this.api.shareAppMessage(
            {
                title:title,
                imageUrl:imageurl,
                query:query
            }
        )
    }
}