import BaseGameSystem from "./BaseGameSystem";
import BoolStorageValue from "./Storage/BoolStorageValue";
import NumberStorageValue from "./Storage/NumberStorageValue";
import StringStorageValue from "./Storage/StringStorageValue";
import ArrayStorageValue from "./Storage/ArrayStorageValue";
import StorageSystem from "./Storage/StorageSystem";

const GM_STORAGE_KEY = "GM_Save";

 export class GmManger extends BaseGameSystem {
    private overRestart: BoolStorageValue;
    private freeTime: BoolStorageValue;
    private hp999: BoolStorageValue;
    private autoNextPage: BoolStorageValue;
    private autoNextPageDelay: NumberStorageValue;
    private itemNotRandom: BoolStorageValue;
    private showRoleId: NumberStorageValue;
    private openBorder: NumberStorageValue;
    private openBorderToggleTime: NumberStorageValue;
    private cusLvOrder: ArrayStorageValue<number>;
    private redemptionCode: StringStorageValue;
    private openGM: BoolStorageValue;
    public static readonly inst: GmManger = new GmManger();

    ClearData() {
        this.overRestart = new BoolStorageValue(GM_STORAGE_KEY + "_overRestart", false);
        this.freeTime = new BoolStorageValue(GM_STORAGE_KEY + "_freeTime", false);
        this.hp999 = new BoolStorageValue(GM_STORAGE_KEY + "_hp999", false);
        this.autoNextPage = new BoolStorageValue(GM_STORAGE_KEY + "_autoNextPage", false);
        this.autoNextPageDelay = new NumberStorageValue(GM_STORAGE_KEY + "_autoNextPageDelay", 3);
        this.itemNotRandom = new BoolStorageValue(GM_STORAGE_KEY + "_itemNotRandom", false);
        this.showRoleId = new NumberStorageValue(GM_STORAGE_KEY + "_showRoleId", 0);
        this.openBorder = new NumberStorageValue(GM_STORAGE_KEY + "_openBorder", 0);
        this.openBorderToggleTime = new NumberStorageValue(GM_STORAGE_KEY + "_openBorderToggleTime", 1);
        this.cusLvOrder = new ArrayStorageValue(GM_STORAGE_KEY + "_cusLvOrder", []);
        this.redemptionCode = new StringStorageValue(GM_STORAGE_KEY + "_redemptionCode", "");
        this.openGM = new BoolStorageValue(GM_STORAGE_KEY + "_openGM", false);
    }

    public get inst() {
        return this;
    }

    public get overRestartValue(): boolean {
        return this.overRestart.GetValue;
    }

    public setOverRestart(value: boolean) {
        this.overRestart.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get freeTimeValue(): boolean {
        return this.freeTime.GetValue;
    }

    public setFreeTime(value: boolean) {
        this.freeTime.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get hp999Value(): boolean {
        return this.hp999.GetValue;
    }

    public setHp999(value: boolean) {
        this.hp999.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get autoNextPageValue(): boolean {
        return this.autoNextPage.GetValue;
    }

    public setAutoNextPage(value: boolean) {
        this.autoNextPage.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get autoNextPageDelayValue(): number {
        return this.autoNextPageDelay.GetValue;
    }

    public setAutoNextPageDelay(value: number) {
        this.autoNextPageDelay.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get itemNotRandomValue(): boolean {
        return this.itemNotRandom.GetValue;
    }

    public setItemNotRandom(value: boolean) {
        this.itemNotRandom.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get showRoleIdValue(): number {
        return this.showRoleId.GetValue;
    }

    public setShowRoleId(value: number) {
        this.showRoleId.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get openBorderValue(): number {
        return this.openBorder.GetValue;
    }

    public setOpenBorder(value: number) {
        this.openBorder.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get openBorderToggleTimeValue(): number {
        return this.openBorderToggleTime.GetValue;
    }

    public setOpenBorderToggleTime(value: number) {
        this.openBorderToggleTime.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get cusLvOrderValue(): any[] {
        return this.cusLvOrder.GetValue;
    }

    public setCusLvOrder(value: any[]) {
        this.cusLvOrder.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get redemptionCodeValue(): string {
        return this.redemptionCode.GetValue;
    }

    public setRedemptionCode(value: string) {
        this.redemptionCode.SetValue = value;
        StorageSystem.Init.Save();
    }

    public get openGMValue(): boolean {
        return this.openGM.GetValue;
    }

    public setOpenGM(value: boolean) {
        this.openGM.SetValue = value;
        StorageSystem.Init.Save();
    }
}
