import { Logger } from "./Logger";
import { EventManager } from "./EventManager";
// import HotUpdate from "./HotUpdate";
import ManifestConfig from "./ManifestConfig";
import DateUtil from "./DateUtil";

export default class VersionManager {

    public static instance: VersionManager = new VersionManager();

    public static Config_Game_Name: Array<string> = [
        "游戏", "斗地主", "血战麻将", '红中麻将'
    ];

    //热更文件下载来后存放文件夹
    public static Config_Key: Array<string> = [
        "main",
        "doudizhu",
        "xz_mj",

        "hz_mj",//红中麻将
        "land_jingdian",
        "xlch_mj",
        "suzhou_mj"

    ];
    public static Version_List: Array<string> = [
        "1.0.0.327",
        "1.0.0.0",
        "1.0.0.0",

        "1.0.0.0",
        "1.0.0.0",
        "1.0.0.0",
        "1.0.0.0"
    ]

    private static Config_ManifestName: string = "project.manifest";

    public iosStoreUrl: string = "";
    public apkStoreUrl: string = "";

    public nowVersion: string = "1.0.0.327"; //网页显示版本号，如果是热更会替换改值
    public targetVersion: string = "1.0.0.1";
    public androidBigVersion: number = 0;
    public iosBigVersion: number = 0

    public isOpenHotUpdate: boolean = true;  //是否打开热更

    private hotUpdateList: Array<HotUpdate> = [];

    private writablePath: string = "";

    private noUpdateIndex: number = -1; //跟随大厅热更的子游戏

    public jumpToPackUpate() {
        let url: string;
        if (cc.sys.isNative) {
            // if (NativeSdkHelper.isIos()) {
            //     url = VersionManager.instance.iosStoreUrl;
            // } else {
            //     url = VersionManager.instance.apkStoreUrl;
            // }
        }
        Logger.info("jumpToPackUpate==androidurl===", VersionManager.instance.apkStoreUrl);
        Logger.info("jumpToPackUpate==iosStoreUrl===", VersionManager.instance.iosStoreUrl);
        Logger.info("jumpToPackUpate=====", url);
        cc.sys.openURL(url);
    }

    public init() {
        // this.reInitAll();
    }
    public reInitAll() {
        this.releaseAll();
        for (let i = 0; i < VersionManager.Config_Key.length; i++) {
            this.reInit(i);
        }
    }

    public releaseAll() {
        for (let i = 0; i < VersionManager.Config_Key.length; i++) {
            if (this.hotUpdateList[i]) {
                this.hotUpdateList[i].disposeUpdate();
            }
        }
    }

    public reInit(index: number) {
        if (!this.hotUpdateList[index]) {
            this.hotUpdateList[index] = new HotUpdate();
        }
        this.hotUpdateList[index].init(index, VersionManager.Config_Key[index], VersionManager.Config_ManifestName);
        if (!this.isOpenHotUpdate) {
            this.hotUpdateList[index].isCheck = true;
            this.hotUpdateList[index].isFinishUpdate = true;
        }
    }

    //根据最新的域名重写热更域名
    public reSetHotUpdateUrl(needCheckUpdate: boolean = true) {
        if (!cc.sys.isNative) return;
        for (let i = 0; i < VersionManager.Config_Key.length; i++) {
            let projectManifestPath: string;
            let preVersionKey: string = "version";
            let preProjectKey: string = "project";
            // Logger.log("nowVersion===", VersionManager.instance.nowVersion);
            this.writablePath = jsb.fileUtils.getWritablePath();
            let mulu: string = this.writablePath + "" + VersionManager.Config_Key[i] + "/";
            if (!jsb.fileUtils.isDirectoryExist(mulu)) {
                jsb.fileUtils.createDirectory(mulu);
                Logger.log("mulu 不存在====", mulu);
            } else {
                Logger.log("mulu 已存在====", mulu);
            }
            projectManifestPath = mulu + preProjectKey + ".manifest";
            Logger.log("projectManifestPath===", projectManifestPath);
            let newJson: string = "";
            let projectJson: object = {};
            if (jsb.fileUtils.isFileExist(projectManifestPath)) {
                let projectManifest: string = jsb.fileUtils.getStringFromFile(projectManifestPath);
                try {
                    projectJson = JSON.parse(projectManifest);
                } catch (error) {
                    projectJson = {};
                    projectJson["version"] = "1.0.0";
                }
                Logger.log("nowVersion222===", projectJson["version"]);
                Logger.log("reSetHotUpdateUrl 读取热更文件======" + projectManifestPath);
            }
            else {
                // let projectManifest: string = jsb.fileUtils.getStringFromFile(mubaoManifestPath);
                let tempKey: string = VersionManager.Config_Key[i];
                Logger.log("tempKey======", tempKey);
                let projectManifest: string = ManifestConfig.getManifestStr(tempKey, i);
                projectJson = JSON.parse(projectManifest);
                Logger.log("reSetHotUpdateUrl 读取本地母包文件======", projectManifest);
                // 这里做了特殊处理，将母包的版本号+1，是为了重写后不在使用母包的manifest，因为如果母包版本号跟可写路径的相同的话，是使用母包的
                // 所以发版时如果是母包要commit 多1次，让版本号+2就没这问题.
                let muBaoVer: string = projectJson["version"];
                projectJson["version"] = muBaoVer;
                Logger.log("母包version===", projectJson["version"]);
                Logger.log("reSetHotUpdateUrl 读取本地母包文件222======", projectJson["remoteVersionUrl"]);
                Logger.log("reSetHotUpdateUrl 读取本地母包文件333======", projectJson["remoteManifestUrl"]);
            }
            // projectJson["packageUrl"] = NetUrlManager.getHotUpdateUrl() + "/hotupdate/" + VersionManager.Config_Url_Key[i] + "/";
            // projectJson["remoteVersionUrl"] = NetUrlManager.getHotUpdateUrl() + "/hotupdate/" + VersionManager.Config_Url_Key[i] + "/" + preVersionKey + ".manifest?t=" + DateUtil.now();
            // projectJson["remoteManifestUrl"] = NetUrlManager.getHotUpdateUrl() + "/hotupdate/" + VersionManager.Config_Url_Key[i] + "/" + preProjectKey + ".manifest?t=" + DateUtil.now();

            newJson = JSON.stringify(projectJson);
            jsb.fileUtils.writeStringToFile(newJson, projectManifestPath);
            Logger.log("reSetHotUpdateUrl projectmainfest packageUrl====", projectJson["packageUrl"]);
            Logger.log("reSetHotUpdateUrl projectmainfest remoteVersionUrl====", projectJson["remoteVersionUrl"]);
            Logger.log("reSetHotUpdateUrl projectmainfest remoteManifestUrl====", projectJson["remoteManifestUrl"]);
            Logger.log("realVersion====", projectJson["version"]);
            if (jsb.fileUtils.isFileExist(projectManifestPath)) {
                Logger.log("重写本地版本文件成功");
            } else {
                Logger.log("重写本地版本文件不成功");
            }
        }
        if (needCheckUpdate) {
            this.reInitAll();
            EventManager.instance.dispatch(HotUpdate.Event_CheckUpdate);
        }

    }

    public getHotUpdate(keyIndex: number) {
        if (VersionManager.instance.isOpenHotUpdate && keyIndex < this.hotUpdateList.length) {
            let hotUpdate: HotUpdate = this.hotUpdateList[keyIndex];
            return hotUpdate
        }
    }

    public checkUpdate(keyIndex: number) {
        if (VersionManager.instance.isOpenHotUpdate && keyIndex < this.hotUpdateList.length) {
            let hotUpdate: HotUpdate = this.hotUpdateList[keyIndex];
            if (cc.sys.isNative) {
                if (keyIndex == this.noUpdateIndex) {//在大厅热更，不用子游戏热更了
                    hotUpdate.isCheck = true;
                    hotUpdate.isFinishUpdate = true;
                    EventManager.instance.dispatch(HotUpdate.Event_On_ALREADY_UP_TO_DATE, VersionManager.Config_Key[keyIndex]);
                } else {
                    hotUpdate.checkUpdate();
                }
            } else {
                hotUpdate.isCheck = true;
                hotUpdate.isFinishUpdate = true;
                EventManager.instance.dispatch(HotUpdate.Event_On_ALREADY_UP_TO_DATE, VersionManager.Config_Key[keyIndex]);
            }
        } else {
            EventManager.instance.dispatch(HotUpdate.Event_On_ALREADY_UP_TO_DATE, VersionManager.Config_Key[keyIndex]);
        }
    }

    public startUpdate(keyIndex: number) {
        let hotUpdate: HotUpdate = this.hotUpdateList[keyIndex];
        hotUpdate.startUpdate();
    }

    public isCheck(keyIndex: number) {
        if (keyIndex < this.hotUpdateList.length) {
            let hotUpdate: HotUpdate = this.hotUpdateList[keyIndex];
            if (keyIndex == this.noUpdateIndex) {
                return true;
            }
            return hotUpdate.isCheck;
        }
        return true;
    }

    public needUpdate(keyIndex: number) {
        if (keyIndex < this.hotUpdateList.length) {
            let hotUpdate: HotUpdate = this.hotUpdateList[keyIndex];
            if (keyIndex == this.noUpdateIndex) {
                return false;
            }
            return hotUpdate.needUpdate;
        }
        return false;
    }

    public isUpdating(keyIndex: number) {
        if (keyIndex < this.hotUpdateList.length) {
            let hotUpdate: HotUpdate = this.hotUpdateList[keyIndex];
            return hotUpdate.isUpdating;
        }
        return false;
    }

    public isFinishUpdate(keyIndex: number) {
        if (keyIndex < this.hotUpdateList.length) {
            let hotUpdate: HotUpdate = this.hotUpdateList[keyIndex];
            if (keyIndex == this.noUpdateIndex) {
                return true;
            }
            return hotUpdate.isFinishUpdate;
        }
        return true;
    }
}