const { ccclass, property } = cc._decorator;

/** 背景大小自适应 */
@ccclass
export default class AutoAdjustBgSize extends cc.Component {

	private originalRatio: number = 1;
	private originalSize: cc.Size = cc.size(0, 0);

    onLoad() {
		this.originalSize = this.node.getContentSize();
		this.originalRatio = this.originalSize.height / this.originalSize.width;
    }

	update(){
		this.adapt();
	}

    private adapt(): void {
        let screenWidth = cc.winSize.width;
        let screenHeight = cc.winSize.height;
        let canvas = cc.Canvas.instance;

        if (canvas.fitHeight && screenWidth/screenHeight > 0.9) {
            this.node.setContentSize(this.originalSize);
            return;
        }


        if (canvas.fitHeight) {
            this.node.width = screenWidth;
            this.node.height = screenWidth * this.originalRatio;
        } else if (canvas.fitWidth) {
            let calculatedWidth = screenHeight / this.originalRatio;
            if (calculatedWidth >= screenWidth) {
                this.node.width = calculatedWidth;
                this.node.height = screenHeight;
            } else {
                this.node.width = screenWidth;
                this.node.height = screenWidth * this.originalRatio;
            }
        }
    }

}
