
import VideoAPI from "../../wx_api/VideoAPI";
import BaseGameSystem from "../BaseGameSystem";
import { VideoAdTarget, IVideoData, IPostVideoAdJson, IPostVideoJson, IPostVideoStatue, VideoResult, IPostVideoRecode } from "./VideoAdAttribute";
import VideoAdJson from "./VideoAdJson";

export class VideoAdManager extends BaseGameSystem {
    ClearData() {
        this.curData = {
            target: VideoAdTarget.Null,
            startTime: null,
            endTime: null,
            result: null,
            ad_log_id: null,
            postError: null,
        }
    }
    curData: IVideoData;
    
    PlayerVideoAd(_adunitid?: string): Promise<boolean> {
        _adunitid = _adunitid || VideoAdJson.videoId;

        return new Promise((resolve, reject) => {
            if(!_adunitid){
                return resolve(true);
            }
            // 小程序
            VideoAPI.Init.ShowRewardedVideoAd(_adunitid).then(res => {
                if (res && res.isEnded || res === undefined) {
                    resolve(true);
                } else {
                    resolve(false);
                }
            });
        });
    }
    
}
const VideoAdSystem = new VideoAdManager();
export default VideoAdSystem;