
import ViewBase from "../../engine/ViewBase";
import GameData from "../GameData";

const {ccclass, property} = cc._decorator;

@ccclass
export default class UnlookView extends ViewBase {

	@property({ type: cc.Sprite, displayName:'' })
	closeBtn: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	unlookLvBtn: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	seeAdBtn: cc.Sprite = null;

	private level: number;

    start () {
		
		this.onAddEvent(this.closeBtn.node,()=>{
			this.closeView();
		})

		this.onAddEvent(this.unlookLvBtn.node,()=>{

		})
		
		this.onAddEvent(this.seeAdBtn.node,()=>{
			
		})
    }
	
	onInitChild(level: number){
		this.level = level;
		
	}

}
