import ViewBase from "../../engine/ViewBase";
import LvOrderItem from "./LvOrderItem";
import { UserDataMgr } from "../../System/User/UserDataMgr";
import GameEventSystem, { GameEvent } from "../../System/GameEvent/GameEvent";

const {ccclass, property} = cc._decorator;

@ccclass
export default class GmLvOrderView extends ViewBase {

	@property({ type: cc.Node, displayName:'' })
	closeBtn: cc.Node = null;

	@property({ type: cc.Node, displayName: '拖拽项' })
	dragItem: cc.Node = null;

	@property({ type: cc.ScrollView, displayName: '滚动视图' })
	scrollView: cc.ScrollView = null;

	@property({ type: cc.Node, displayName: '保存按钮' })
	saveBtn: cc.Node = null;

	@property({ type: cc.Prefab, displayName: '关卡项预制体' })
	itemPrefab: cc.Prefab = null;

	private itemMap: Map<number, cc.Node> = new Map();
	private lvOrder: number[] = null;
	private dragIndex: number = -1;
	private startDragItem: LvOrderItem = null;
	private placeItem: LvOrderItem = null;
	private dragLvOrderItem: LvOrderItem = null;

	onLoad(): void {
		this.onAddEvent(this.saveBtn, () => {
			this.onSave();
		});
		this.onAddEvent(this.closeBtn, () => {
			this.closeView();
		});
	}
	onInitChild(level: number){
		this.lvOrder = UserDataMgr.instance.GetLvOrder();
		this.initItems();
	}

	private initItems() {
		for (let i = 0; i < this.lvOrder.length; i++) {
			let id = this.lvOrder[i];
			let itemNode = cc.instantiate(this.itemPrefab);
			let lvOrderItem = itemNode.getComponent(LvOrderItem);
			if (lvOrderItem) {
				lvOrderItem.init(id, i, this);
			}
			this.scrollView.content.addChild(itemNode);
			this.itemMap.set(i, itemNode);
		}
		
		this.scheduleOnce(() => {
			let layout = this.scrollView.content.getComponent(cc.Layout);
			if (layout) {
				layout.enabled = false;
			}
		});
	}

	onItemTouchStart(event: cc.Event.EventTouch, item: LvOrderItem) {
		this.scrollView.enabled = false;
		this.startDragItem = item;
		this.dragIndex = item.index;
		this.dragItem.active = true;
		
		if (!this.dragLvOrderItem) {
			this.dragLvOrderItem = this.dragItem.getComponent(LvOrderItem);
		}
		
		this.dragLvOrderItem.init(item.id, item.index, null);
		let pos = this.dragItem.parent.convertToNodeSpaceAR(event.getLocation());
		this.dragItem.setPosition(pos);
	}

	onItemTouchMove(event: cc.Event.EventTouch, item: LvOrderItem) {
		let pos = this.dragItem.parent.convertToNodeSpaceAR(event.getLocation());
		this.dragItem.setPosition(pos);

		if (this.isContain(this.scrollView.node, event.getLocation())) {
			if (this.placeItem) {
				if (!this.isContain(this.placeItem.node, event.getLocation())) {
					this.placeItem.updateName();
					this.placeItem = null;
				}
			}

			let n = this.getItemUnderTouch(event.getLocation());
			if (n) {
				let lvOrderItem = n.getComponent(LvOrderItem);
				if (lvOrderItem && (!this.placeItem || this.placeItem.index != lvOrderItem.index) && lvOrderItem.id != this.dragLvOrderItem.id) {
					this.placeItem = lvOrderItem;
					this.placeItem.nameLbl.string = this.dragLvOrderItem.nameLbl.string;
				}
			}
		}
	}

	onItemTouchEnd(event: cc.Event.EventTouch, item: LvOrderItem) {
		this.scrollView.enabled = true;
		this.dragItem.active = false;

		if (this.placeItem) {
			let tempID = this.lvOrder[this.startDragItem.index];
			this.lvOrder[this.startDragItem.index] = this.lvOrder[this.placeItem.index];
			this.lvOrder[this.placeItem.index] = tempID;
			this.startDragItem.changeId(this.placeItem.id);
			this.placeItem.changeId(tempID);
			this.startDragItem = null;
			this.placeItem = null;
		}
	}

	onSave() {
		GameEventSystem.dispatch(GameEvent.UpdateLvOrder);
		UserDataMgr.instance.SaveLvOrder(this.lvOrder);
		this.closeView();
	}

	private isContain(node: cc.Node, worldPos: cc.Vec2): boolean {
		let rect = new cc.Rect(node.x - node.width * node.anchorX, node.y - node.height * node.anchorY, node.width, node.height);
		let localPos = node.parent.convertToNodeSpaceAR(worldPos);
		return rect.contains(localPos);
	}

	private getItemUnderTouch(worldPos: cc.Vec2): cc.Node {
		if (!this.scrollView.content) return null;

		for (let i = 0; i < this.scrollView.content.childrenCount; i++) {
			let child = this.scrollView.content.children[i];
			if (this.isContain(child, worldPos)) {
				return child;
			}
		}
		return null;
	}
}
