export interface IAdpter {
    nativefiles : any[];
    autoCacheFile : boolean;
    CleanAllNativeFile();
    SaveCustionFileList();
}


/** 定义全局常量 */
declare global {
    /** app抖音平台 */
    const CC_CUSTOM_TT: boolean;
    /** 小游戏QQ平台 */
    const CC_CUSTOM_QQ: boolean;
}

/** 构建面板渠道选项 */
export const CustomGlobalConst = {
    CC_CUSTOM_TT: false,
    CC_CUSTOM_QQ: false,
}

if(!CC_EDITOR){
    for (const key in CustomGlobalConst) { 
        window[key] = window[key] || CustomGlobalConst[key]
    }
}