import FguiButton from "./FguiButtom";

export class FguiButton2 extends FguiButton {
    _context: any;
    args: any[];

    constructor(name: string, view: fgui.GComponent, func: Function, context: any, ...args) {
        super(name, view, func);
        this._context = context;
        this.args = args;
        return this;
    }

    protected OnClick(evt: fgui.Event) {
        if (!this.com) return;
        this.func.call(this._context, this, ...this.args);
    }

    Dispose(): void {
        super.Dispose();
        this.args = null;
        this._context = null;
    }
}