/**
 * 回调管理器
 * 用于管理回调，防止对象被释放后回调还被调用
 */
export class HandlerManager {
    private id: number = 0;
    private callbackMap: Map<any, Map<number, Function>> = new Map<number, any>();
    private pool: Map<number, Function>[] = [];

    /**
     * 管理回调
     * @param once 是否执行一次后自动移除
     * @param caller 回调作用域
     * @param method 回调方法
     */
    public Add<T extends Function>(once: boolean, caller: any, method: T): T {
        let id = this.id++;

        let map = this.callbackMap.get(caller);
        if (map == null) {
            map = this.GetMap();
            this.callbackMap.set(caller, map);
        }
        map.set(id, method);

        let _callbackMap = this.callbackMap;
        function _method () {
            // 检测回调的作用域是否被移除
            let map = _callbackMap.get(caller);
            if (map != null) {
                let method = map.get(id);
                if (method != null) {
                    method.apply(caller, arguments);
                }
            }
        }
        // @ts-ignore
        return _method;
    }


    /** 清除回调 */
    public Clear(caller: any) {
        this.callbackMap.delete(caller);
    }

    /** 清除回调 */
    public ClearAll() {
        this.callbackMap.clear();
        this.pool.length = 0;
    }

    /** 清除回调 */
    public ClearByMethod(caller: any, method: Function) {
        let map = this.callbackMap.get(caller);
        if (map != null) {
            for (let i of map) {
                if (i[1] == method) {
                    map.delete(i[0]);
                    if(map.size == 0){
                        this.pool.push(map);
                        this.callbackMap.delete(caller);
                    }
                    break;
                }
            }
        }
    }

    private GetMap(){
        let map = this.pool.length > 0 ? this.pool.pop() : new Map<number, Function>();
        return map;
    }
}