import ViewBase from "../../engine/ViewBase";
import { GameJsonConfig } from "../../GameJsonConfig";
import { ViewConfig } from "../../System/ui/UI_Config";
import UIManager from "../../System/ui/UIManager";
import GameData from "../GameData";
import { UserDataMgr } from "../../System/User/UserDataMgr";
import VideoAdSystem from "../../System/VideoAd/VideoAdManager";
import { GmManger } from "../../System/GmManger";
import Singleton from "../../singleton/Singleton";

const {ccclass, property} = cc._decorator;

@ccclass
export default class SettlementView extends ViewBase {

	@property({ type: cc.Node, displayName:'' })
	fhBtn: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	shareBtn: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	failNode: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	winNode: cc.Node = null;

	@property({ type: cc.Sprite, displayName:'' })
	replayBtn: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	failIcon: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	winIcon: cc.Sprite = null;

	@property({ type: cc.Node, displayName:'' })
	nextLvBtn: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	retHomeBtn: cc.Node = null;
	level: number;

	onLoad(){

		this.onAddEvent(this.replayBtn.node, ()=>{
			this.closeView();
			GameData.gotoLevel(GameData.CurGM.Level);
		})

		this.onAddEvent(this.nextLvBtn, ()=>{
			this.closeView();
			this.NextLv();
		})
		
		this.onAddEvent(this.retHomeBtn, ()=>{
			this.StopGame();
			this.closeView();
			
            UIManager.instance.showView(ViewConfig.HomeView,()=>{
            })
		})

		this.onAddEvent(this.fhBtn, async ()=>{
			let scucess = await VideoAdSystem.PlayerVideoAd();
			if(!scucess) return;
			
			this.closeView();
			GameData.CurGM.revive();
		})

		this.onAddEvent(this.shareBtn, ()=>{
			// this.closeView();
			// GameData.CurGM.shareGame();
		})
		
	}

	start () {
		if(GmManger.inst.overRestartValue){
			this.closeView();
			GameData.gotoLevel(GameData.CurGM.Level);
		}
	}

	StopGame(){
		GameData.CurGM.EndGame();
		GameData.CurGM = null;
	}

	NextLv(){
		GameData.CurGM.gotoNextLevel();
	}

	onInitChild(is_win: boolean){
		const gameMode = UserDataMgr.instance.GetSelectedGameMode();
		this.nextLvBtn.active = is_win && GameJsonConfig.getNextLevel(GameData.CurGM.Level, gameMode) != null;
		this.winNode.active = is_win;
		this.failNode.active = !is_win;

		Singleton.SoundSystem.StopBgm();
	}

}
