const { ccclass, property, executeInEditMode, disallowMultiple } = cc._decorator;

/**
 * 当父节点大小改变时，自动调整本节点位置
 */
@ccclass
@executeInEditMode
@disallowMultiple
export default class ImagePositionAdjuster extends cc.Component {

    @property({ tooltip: '是否开启 X 轴自动调整' })
    enableX = true;

    @property({ tooltip: '是否开启 Y 轴自动调整' })
    enableY = true;

    @property({ tooltip: 'X 轴跟随系数 (0: 锁定左边, 1: 锁定右边)', range: [0, 1, 0.01] })
    xFactor = 0.5;

    @property({ tooltip: 'Y 轴跟随系数 (0: 锁定下边, 1: 锁定上边)', range: [0, 1, 0.01] })
    yFactor = 0.5;

    @property({ tooltip: '是否实时监测' })
    realTime = true;

    _startParentWidth = 0;
    _startParentHeight = 0;
    _isInitialized = false;
    _parentCache = null;
    _startPos = cc.v2();

    onLoad() {
        this._initData();
    }

    onEnable() {
        if (!this._isInitialized) {
            this._initData();
        }
    }

    onDisable() {
    }

    recalibrate() {
        this._isInitialized = false;
        this._initData();
    }

    _initData() {
        const parent = this.node.parent;
        if (!parent) {
            return;
        }

        this._parentCache = parent;
        const parentSize = parent.getContentSize();
        
        this._startParentWidth = parentSize.width;
        this._startParentHeight = parentSize.height;
        this._startPos = this.node.getPosition();
        this._isInitialized = true;
    }

    update(dt) {
        if (!this.realTime) {
            return;
        }

        if (!this._isInitialized || !this._parentCache) {
            if (this.node.parent) {
                this.recalibrate();
            }
            return;
        }

        const parent = this._parentCache;
        const currentSize = parent.getContentSize();

        const deltaW = currentSize.width - this._startParentWidth;
        const deltaH = currentSize.height - this._startParentHeight;

        if (Math.abs(deltaW) < 0.001 && Math.abs(deltaH) < 0.001) {
            return;
        }

        if (this.enableX && Math.abs(deltaW) > 0.001) {
            this.node.x =  this._startPos.x < 0 ? this._startPos.x - deltaW * this.xFactor 
                : this._startPos.x + deltaW * this.xFactor;
            // this._startParentWidth = currentSize.width; // 更新基准
        }

        if (this.enableY && Math.abs(deltaH) > 0.001) {
            this.node.y = this._startPos.y < 0 ? this._startPos.y - deltaH * (this.yFactor * 0.5) 
                : this._startPos.y + deltaH * (this.yFactor * 0.5);
            // this._startParentHeight = currentSize.height; // 更新基准
        }

    }
}