
import { GameEvent } from "../../System/GameEvent/GameEvent";
import { UserDataMgr } from "../../System/User/UserDataMgr";
import VideoAdSystem from "../../System/VideoAd/VideoAdManager";
import UIManager from "../../System/ui/UIManager";
import { UI_Config, ViewConfig } from "../../System/ui/UI_Config";
import ViewBase from "../../engine/ViewBase";
import Singleton from "../../singleton/Singleton";

const {ccclass, property} = cc._decorator;

@ccclass
export default class SettingView extends ViewBase {

	@property({ type: cc.Node, displayName:'' })
	gmBtn: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	soundCon: cc.Node = null;

	@property({ type: cc.Node, displayName:'' })
	musicCon: cc.Node = null;


	@property({ type: cc.Sprite, displayName:'' })
	closeBtn: cc.Sprite = null;

	private level: number;

	private currentMusicVolume: number = 1.0;
	private currentSoundVolume: number = 1.0;

    start () {
		
		this.onAddEvent(this.closeBtn.node,()=>{
			this.closeView();
		})

		
		this.onAddEvent(this.gmBtn,()=>{
			this.closeView();
			UIManager.instance.showView(ViewConfig.GmView);
		})

		this.initMusicCon();
		this.initSoundCon();
    }

	initMusicCon(){
		let slider = this.musicCon.getChildByName('slider');
		let sliderComp = slider.getComponent(cc.Slider);
		let progressBar = slider.getChildByName('progressBar').getComponent(cc.ProgressBar);

		// 加载保存的音量值，默认1.0
		let volume = UserDataMgr.instance.GetMusicVolume();
		sliderComp.progress = volume;
		progressBar.progress = volume;
		this.currentMusicVolume = volume;

		// 监听滑动事件
		sliderComp.node.on('slide', this.onMusicSliderChange, this);
	}

	initSoundCon(){
		let slider = this.soundCon.getChildByName('slider');
		let sliderComp = slider.getComponent(cc.Slider);
		let progressBar = slider.getChildByName('progressBar').getComponent(cc.ProgressBar);

		// 加载保存的音量值，默认1.0
		let volume = UserDataMgr.instance.GetSoundVolume();
		sliderComp.progress = volume;
		progressBar.progress = volume;
		this.currentSoundVolume = volume;

		// 监听滑动事件
		sliderComp.node.on('slide', this.onSoundSliderChange, this);
	}

	private onMusicSliderChange(slider: cc.Slider) {
		let progress = slider.progress;
		let progressBar = slider.node.getChildByName('progressBar').getComponent(cc.ProgressBar);
		progressBar.progress = progress;
		this.currentMusicVolume = progress;
		UserDataMgr.instance.SetMusicVolume(this.currentMusicVolume, false);
		// 移除实时保存，在关闭时保存
	}

	private onSoundSliderChange(slider: cc.Slider) {
		let progress = slider.progress;
		let progressBar = slider.node.getChildByName('progressBar').getComponent(cc.ProgressBar);
		progressBar.progress = progress;
		this.currentSoundVolume = progress;
		UserDataMgr.instance.SetSoundVolume(this.currentSoundVolume, false);
		// 移除实时保存，在关闭时保存
	}

	onDisable(): void {
		// 保存音量设置
		UserDataMgr.instance.SetMusicVolume(this.currentMusicVolume, true);
		UserDataMgr.instance.SetSoundVolume(this.currentSoundVolume, true);

		// 移除事件监听, 不用移除了，因为节点会被销毁
		// let musicSlider = this.musicCon.getChildByName('slider');
		// if (musicSlider) {
		// 	musicSlider.off('slide', this.onMusicSliderChange, this);
		// }
		// let soundSlider = this.soundCon.getChildByName('slider');
		// if (soundSlider) {
		// 	soundSlider.off('slide', this.onSoundSliderChange, this);
		// }
		Singleton.GameEventSystem.dispatch(GameEvent.UP_HOME_UI);
	}
	
	onInitChild(level: number){
		this.level = level;
		
	}

}
