import Tools from "../Tools/Tools";

export class EngineConfig {

    public static EnvironmentType = {
        Dev: 0,  //开发环境
        Test: 1,  //测试环境
        Online: 2, //线上环境
    }

    // 环境
    public static environment: number = cc.sys.platform == cc.sys.QQ_PLAY || cc.sys.platform == cc.sys.BYTEDANCE_GAME || cc.sys.platform == cc.sys.WECHAT_GAME ? EngineConfig.EnvironmentType.Online : EngineConfig.EnvironmentType.Dev;
}