import BasePlatformAPI from "./BasePlatformAPI";

export default class NetAPI extends BasePlatformAPI {

    private static net : NetAPI = null;
	public static get Init() : NetAPI{
		if(this.net == null){
			this.net = new NetAPI();
		}
		return this.net;
	}

    private constructor(){
        super();
        this.api.onNetworkStatusChange(this.OnNetworkStatusChange.bind(this));
    }

    private onchange : Array<{callback : Function , thisobj : any}> = [];

    /** 获取网络状态 */
    public GetNetworkType() : Promise<{networkType : string}>{
        if(!this.api) return new Promise((r,j)=>{
            r({networkType : "none"});
        });
        return new Promise((r,j)=>{
            this.api.getNetworkType({
                success (res) {
                    r(res);
                }
            });
        });        
    }


    public AddOnNetworkStatusChangeEventListener(callback : Function , thisobj : any){
        if(!this.api) return;
        this.onchange.push({callback:callback , thisobj:thisobj});
    }

    public RemoveOnNetworkStatusChangeListener(callback : Function , thisobj : any){
        if(!this.api) return;
        const removehideeventlistener = (callback , thisobj) => {
            const item : {callback : Function , thisobj : any} = this.onchange.filter(item => item.callback === callback && item.thisobj === thisobj)[0];
            const index =  this.onchange.indexOf(item , 0);
            if(index == -1) return;
            if(index == 0) {this.onchange.shift(); return;}
            else if(index == this.onchange.length-1) {this.onchange.pop(); return;}
            else{
                this.onchange.splice(index , 1);
            }
        };
        removehideeventlistener(callback , thisobj);
    }

    /** 网络状态改变 */
    private OnNetworkStatusChange(res : any){
        if(!this.api) return;
        for(let item of this.onchange){
            item.callback.call(item.thisobj , res);
        }
    }
}