export default class BasePlatformAPI {

    /** wx or tt */
    protected api: any;

    constructor() {
        if (window["wx"]) {
            this.api = window["wx"];
            // cc.warn("当前环境 为 wx")
        }
        else if (window["tt"]) {
            this.api = window["tt"];
            // cc.warn("当前环境 为 tt")
        }
        else {
            this.api = null;
            // cc.warn("当前环境 为 null")
        }
    }
}