import Singleton from "../singleton/Singleton";
import { EventManager } from "./EventManager";
import { Logger } from "./Logger";

const { ccclass, property } = cc._decorator;

@ccclass
export default class ComponentBase extends cc.Component {
   
   
    //是否已经初始化节点
    public isInit: boolean = false;

    onLoad() {
        // Logger.log("ComponentBase onLoad",this.name)
    }

    start() {
        
    }

    onEnable() {

    }

    onDisable() {
        // this._dispose();
    }


    /**获得子节点 */
    public findChild(parent: cc.Node, path: string): cc.Node {
        let paths: Array<string> = path.split("/");
        let child: cc.Node = parent;
        if (paths) {
            for (let i = 0; i < paths.length; ++i) {
                child = parent.getChildByName(paths[i]);
                parent = child;
                if (!parent) {
                    Logger.warn(`findChild ----------- ${path}  parent is null`);
                    return;
                }
            }
        }
        return child;
    }
    /** 获取子节点 或者 子节点组件 */
    public getChild(parent: cc.Node, childName: string, childType: any = cc.Node): any {
        if (!parent) {
            Logger.warn(`getChild ----------- ${childName}  parent is null`);
            return;
        }
        if (childType == cc.Node)
            return this.findChild(parent, childName);
        return this.findChild(parent, childName)?.getComponent(childType);
    }

    public static addBtnEvent(btnDisplay: cc.Node, callback: Function, transition: cc.Button.Transition = cc.Button.Transition.COLOR) {
        if (!btnDisplay.getComponent(cc.Button)) {
            btnDisplay.addComponent(cc.Button)
        }
        btnDisplay.getComponent(cc.Button).transition = transition;
        btnDisplay.targetOff(btnDisplay);
        btnDisplay.on(cc.Node.EventType.TOUCH_END, () => {
            if (btnDisplay.getComponent(cc.Button).enabled && btnDisplay.opacity > 0) {
                //加点击音效
                callback && callback();
            }
        }, btnDisplay);
    }

    public onAddEvent(btnDisplay: cc.Node, callback: Function, transition: cc.Button.Transition = cc.Button.Transition.COLOR) {
        if (!btnDisplay.getComponent(cc.Button)) {
            btnDisplay.addComponent(cc.Button)
        }
        btnDisplay.getComponent(cc.Button).transition = transition;
        btnDisplay.targetOff(btnDisplay);
        btnDisplay.on(cc.Node.EventType.TOUCH_END, (event: cc.Event.EventTouch) => {
            if (btnDisplay.getComponent(cc.Button).enabled && btnDisplay.opacity > 0) {
                //加点击音效
                let globalP: cc.Vec2 = event.getLocation()
                let tx: number = globalP.x - cc.winSize.width / 2;
                let ty: number = globalP.y - cc.winSize.height / 2;
                // GameController.instance.playDianji(cc.v2(tx, ty))
                Singleton.SoundSystem.PlaySound("resources", "sound/click");
                callback && callback(event);
            }
        }, btnDisplay);
    }

    private _dispose() {
        this.node.stopAllActions();
        this.unscheduleAllCallbacks();
        // Logger.log("_dispose==", this.name)
        EventManager.instance.clear(this);
    }

}
