import BaseStorageValue from "./BaseStorageValue";

/**数组类型保存 */
export default class ArrayStorageValue<T extends number|string|boolean> extends BaseStorageValue<T[]> {

    private cur_json_value : string;

    set SetValue(value : T[]){
        this.value = value;
    }
    get GetValue(): T[] {
        return this.value;
    }
    
    public constructor(key : string , value : Array<T> , monitor : boolean = true){
        super(key , value , monitor);
    }

    Save(_force : boolean = false) : any {
        const _cur_v = JSON.stringify(this.value);
        if(this.cur_json_value == _cur_v && !_force){
            return null;
        }
        this.cur_json_value = _cur_v;
        return _cur_v;
    }
    Load(value: any): T[] {
        if(value == undefined || !value || value === "") return;
        let _value = JSON.parse(value);
        if(this.value.length > _value.length){
            for(let i = 0 ; i < _value.length ; i++){
                this.value[i] = _value[i];
            }
        }else{
            this.value = _value;
        }
        this.cur_json_value = JSON.stringify(this.value);
        this.change = true;
    }
}