import PlatformManager from "../System/Platform/PlatformManager";
import Timer from "./Timer";

class JsbFileTools {

    // private fs = CC_JSB ? jsb.fileUtils : wx.getFileSystemManager();
    private root_url = CC_JSB ? jsb.fileUtils.getWritablePath() : PlatformManager.InPlatform ? wx.env.USER_DATA_PATH+'/' : "web/";
    private webCache: {[key: string]: any};
    constructor(){
        // 浏览器跨域用不了oss缓存
        if(!CC_JSB && !PlatformManager.InPlatform){
            this.LoadWebCache();
        }
    }

    public WriteFile(_info : string ,  _path : string){
        return new Promise((r,j)=>{   
            let _to_path = this.root_url+_path;
            let _succ = false;

            if(CC_JSB){
                let _arr_buffer = this.stringToArrayBuffer(_info);
                this.ReadWriteModel(_arr_buffer , _arr_buffer.length , false);
                _succ = jsb.fileUtils.writeDataToFile(_arr_buffer, _to_path) // 原生

            }else if(PlatformManager.InPlatform){
                try{
                    let _arr_buffer = this.stringToArrayBuffer(_info);
                    this.ReadWriteModel(_arr_buffer , _arr_buffer.length , false);
                    wx.getFileSystemManager().writeFileSync(_to_path, _arr_buffer.buffer, 'binary') // 微信
                    _succ = true;
                }catch(e){
                    console.error(e);
                    _succ = false;
                }
            }else{
                // 浏览器
                this.webCache[_path] = _info;  
                Timer.callLater(this, this.SaveWebCache, 0, 'SaveWebCache')
            }

            _succ ? r(this.root_url+_path) : j("保存失败"+this.root_url+_path);
        });
    }

    private IsFileExist(_path : string){
        if(CC_JSB){
            return jsb.fileUtils.isFileExist(_path);
        }else if(PlatformManager.InPlatform){
            try{
                wx.getFileSystemManager().accessSync(_path);
                return true;
            }catch(e){
                return false;
            }
        }else{
            return this.webCache[_path] ? true : false;
        }
    }

    public ReadFile(_path : string){
        return new Promise<string>((resolve, reject)=>{
            let _r_path = this.root_url+_path;
            if(this.IsFileExist(_r_path)){
                if(!this.webCache){
                    let _buff = this.GetDataFromFile(_r_path);
                    this.ReadWriteModel(_buff , _buff.length , true);
                    let _str = this.arrayBufferToString(_buff);
                    resolve(_str);
                }else{
                    resolve(this.webCache[_r_path]);
                }
            }else{
                reject("文件"+_r_path+"不存在");            
            }
        });
    }

    public GetDataFromFile(_path : string) {
        try{
            return CC_JSB ? jsb.fileUtils["getDataFromFile"](_path) : 
            PlatformManager.InPlatform ? new Uint8Array(wx.getFileSystemManager().readFileSync(_path, '') as ArrayBuffer) : 
                this.webCache[_path];
        }catch(e){
            console.error(e);
            return ;
        }
    }

    public DeleteFile(_path : string){
        let _r_path = this.root_url+_path;
        if(this.IsFileExist(_r_path)){
            if(CC_JSB){
                return jsb.fileUtils.removeFile(_r_path)
            }else if(PlatformManager.InPlatform){
                try{
                    wx.getFileSystemManager().unlinkSync(_r_path)
                    return true;
                }catch(e){
                    console.warn("删除文件失败"+_r_path, e);
                    return false;
                }
            }else{
                delete this.webCache[_r_path];
            }
            return true;
        }
    }
    
    private IsDirectoryExist(path : string){
        return CC_JSB ? jsb.fileUtils.isDirectoryExist(path) : 
            PlatformManager.InPlatform ? this.IsFileExist(path) : true;
    }

    private ReadWriteModel(_str : Buffer | Uint8Array , _len : number , is_read : boolean){        
        let sum = 0;
        for(let i = 0 ; i < _len ; i++){
            _str[i] = _str[i] + ((is_read ? -1 : 1) * ((sum + i*i) >>> 2));
            sum += i & 3;
        }
    }

    public CreateDir(_path : string){
        if(!this.IsDirectoryExist(this.root_url+_path)){
            CC_JSB ? jsb.fileUtils.createDirectory(this.root_url+_path) :
                PlatformManager.InPlatform ?  wx.getFileSystemManager().mkdirSync(this.root_url+_path) : false;
        }
        return true;
    }

    public DeleteDir(_path: string){
        
        var fileList = [];

        if (this.IsDirectoryExist(_path)) {
            jsb.fileUtils.listFilesRecursively(_path, fileList);
            fileList.forEach(srcPath => {
                jsb.fileUtils.removeFile(srcPath);
            })
            return jsb.fileUtils.removeDirectory(_path);
        }
        return false;
    }
    
    /** web 文件缓存 */
    private SaveWebCache() {
        let zipdata = pako.deflate(JSON.stringify(this.webCache));
        cc.sys.localStorage.getItem('__webCache')
        let str_zipdata = "";
        for (let i = 0; i < zipdata.length; i++) {
            str_zipdata += String.fromCharCode(zipdata[i]);
        }
        cc.sys.localStorage.setItem("__webCache", str_zipdata);
    }
    
    /** web 文件缓存 */
    private LoadWebCache() {
        if(this.webCache) {
            return this.webCache;
        }

        let str_zipdata = cc.sys.localStorage.getItem('__webCache');
        if(str_zipdata == null) {
            return this.webCache = {}
        }

        let zipdata = new Uint8Array(str_zipdata.length);
        for (let i = 0; i < str_zipdata.length; i++) {
            zipdata[i] = str_zipdata.charCodeAt(i);
        }
        let body = pako.inflate(zipdata);
        let str  = new TextDecoder("utf-8").decode(body);
        this.webCache = JSON.parse(str);
        return this.webCache;
    }

    private stringToArrayBuffer(str: string): Uint8Array | Buffer {  
        if(Buffer){
            const buffer = Buffer.from(str, 'utf8'); // jsb原生buffer
            return buffer;
        }else if(window.TextEncoder){
            const encoder = new TextEncoder(); // TextEncoder是Web API的一部分，用于将字符串编码为Uint8Array
            const uint8Array = encoder.encode(str);  
            return uint8Array;  
        }else{
            // 将字符串编码为UTF-8字节序列
            const arr = unescape(encodeURIComponent("中文abc")).split("").map(val => val.charCodeAt(0));
            // 创建一个Uint8Array视图，将字节序列存储在其中
            const uint8Array = new Uint8Array(arr);
            return uint8Array;
        }
    }
    
    private arrayBufferToString(_buff:  Uint8Array): string {  
        if(Buffer){
            return Buffer.from(_buff).toString('utf8') // jsb原生buffer
        }else if(window.TextDecoder){
            const decoder = new TextDecoder(); // web
            return decoder.decode(_buff);
        }else{
            // String.fromCharCode.apply(null, array); // 调用栈溢出
            var res = '';
            var chunk = 8 * 1024;
            var i = 0;
            for (i = 0; i < _buff.length / chunk; i++) {
                res += String.fromCharCode.apply(null, _buff.slice(i * chunk, (i + 1) * chunk));
            }
            res += String.fromCharCode.apply(null, _buff.slice(i * chunk));
            return decodeURIComponent(escape(res));
        }
    }
}
export const JsbFileToolsSystem = new JsbFileTools(); 
