/**
 * Spine帧缓存
 */

export class SpineFboManager {
    static rectBuffer: { [key: string]: {[key: string] : cc.Rect} } = {};
    
    static GetSpineTime(spine: sp.Skeleton): number {
        let dt: number;
        if (spine['_curFrame'] != null) {
            // 动画类型为缓存/非实时计算模式
            dt = spine['_accTime'];
        } else {
            // 实时计算模式
            let trackEntry: sp.spine.TrackEntry = spine.getCurrent(0);
            if (trackEntry) {
                dt = trackEntry.trackTime;
            }
        }
        if (dt == null) {
            console.warn("SpineFboManager.GetSpineFps: dt is null")
            return;
        }
        
        return dt
    }

    static GetSpineWorldRect(spine: sp.Skeleton,dt: number, fps: number): cc.Rect {
        // if(this.rectx) return this.rectx;
        if(CC_DEBUG && spine.skeletonData['_uuid'] == null){
            console.error("SpineFboManager.GetSpineWorldRect: spine.skeletonData['_uuid'] is null")
            debugger;
        }
        // 找缓存
        let bufs = this.rectBuffer[spine.skeletonData['_uuid']] || (this.rectBuffer[spine.skeletonData['_uuid']] = {});
        if(bufs){
            let rect = bufs[fps];
            if(rect) return rect;
        }
        // 没有缓存则计算
        if(spine.isAnimationCached()){
            let cache = spine['_frameCache']
            if(spine['_frameCache']){
                let skeletonInfo = cache._skeletonInfo
                let skeleton = skeletonInfo.skeleton;
                let state = skeletonInfo.state;

                let animation = skeleton.data.findAnimation(cache._animationName);
                state.setAnimationWith(0, animation, false);
                skeleton.update(dt);
                state.update(dt);
                state.apply(skeleton);
                skeleton.updateWorldTransform();
            }
        }

        let rect = cc.rect();
        let hasData = false;
        if (spine) {
            if (spine['_skeleton']) {
                let offset = {
                    x: 0,
                    y: 0,
                    set: function (x: number, y: number) {
                        this.x = x;
                        this.y = y;
                    }
                }
                let size = {
                    x: 0,
                    y: 0,
                    set: function (x: number, y: number) {
                        this.x = x;
                        this.y = y;
                    }
                }
                let tmp = new Array();
                spine['_skeleton'].getBounds(offset, size, tmp);
                rect.x = offset.x;
                rect.y = offset.y;
                rect.width = size.x;
                rect.height = size.y;
                hasData = true;
            }
        }
        if (!hasData || (rect.x == 0 && rect.y == 0 && rect.width == 0 && rect.height == 0)) {
            rect.x = -50;
            rect.y = -50;
            rect.width = 100;
            rect.height = 100;
        }
        bufs[fps] = rect;
        return rect;
    }
}


const {ccclass, property} = cc._decorator;
@ccclass 
export default class SpineFBO extends cc.Component {
    // preprocess-class.js 文件加载数据
	@property({ type: cc.Sprite, displayName: '显示缓存Node' })
	protected spriteFBO: cc.Sprite = null;

	@property({ displayName: '启动时刷新帧快照' })
	public isStartUpdate: boolean = false;

	@property({ displayName: '自动刷新快照间隔' })
	protected autoUpdateDt: number = -1;

    protected camera : cc.Camera = null;
	protected parentGroup: string = 'default';
	protected parentGroupIdx: number = 0;
	protected emptyGroupIdx: number = 0;
	protected isInit: boolean = false;
	protected oldPos: cc.Vec2 = cc.v2();
	protected _waitFps: number = -1;
	protected renderTexture: cc.RenderTexture = null;
    protected spine: sp.Skeleton;
    private _worldPos: cc.Vec2 = cc.v2();
    protected fps: number = -1;
    protected animName: string = '';
    rect: cc.Rect;
    

    protected onLoad (): void {
		
		if (!this.spriteFBO){
			let node = new cc.Node()
			this.node.parent.addChild(node,this.node.zIndex+1,'SpriteFBO')
			this.spriteFBO = node.addComponent(cc.Sprite)
		}

		this.spriteFBO.spriteFrame = new cc.SpriteFrame()
		this.spriteFBO.spriteFrame.setFlipY(true)
		this.spriteFBO.node.setPosition(this.node.convertToNodeSpaceAR(cc.Vec2.ZERO));
		this.spriteFBO.node.anchorX = 0.5;
		this.spriteFBO.node.anchorY = 0.5;
		
		this.node['__isNodeFBO'] = true;
		this.oldPos.x = this.node.x;
		this.oldPos.y = this.node.y;
		this.SetAutoUpdateDt(this.autoUpdateDt)
    }



	protected start(): void {
        this.spine = this.node.getComponent(sp.Skeleton);
        this.spriteFBO.node.group = this.spine.node.group;
        this.spriteFBO.node.setContentSize(this.spine.node.getContentSize());
		this.RefreshCamera()
		this.isInit = true;
		if(this.isStartUpdate){
			this.UpdateFBO()
		}
	}

	public EnableEvents(): void {
		// cc.director.off(cc.Director.EVENT_BEFORE_DRAW, this.OnBeforeRenderScene, this);
		// cc.director.on(cc.Director.EVENT_BEFORE_DRAW, this.OnBeforeRenderScene, this);
		// cc.director.on(cc.Director.EVENT_AFTER_DRAW, this.OnAfterRenderScene, this);
	}

	public DisableEvents(): void {
		// cc.director.off(cc.Director.EVENT_BEFORE_DRAW, this.OnBeforeRenderScene, this);
		// cc.director.off(cc.Director.EVENT_AFTER_DRAW, this.OnAfterRenderScene, this);
	}

    protected lateUpdate(dt: number): void {
        this.OnBeforeRenderScene();
        this.UpdateNodeFBOTransform();
    }

	protected onEnable() {
		// 子节点触发冒泡事件例子: this.node.dispatchEvent(NodeFBO.Event_UpdateFBO);
		this.isInit && this.EnableEvents()
		this.spriteFBO.node.opacity = 255;
	}

	protected onDisable() {
		// this._waitFps = -1;
		this.spriteFBO.node.opacity = 0;
		this.DisableEvents()
	}

	
	/**
	 * 设置自动刷新快照间隔
	 * @param dt 
	 * @returns 
	 */
	SetAutoUpdateDt(dt: number): void {
		this.autoUpdateDt = dt;
		this.unschedule(this.UpdateFBO);
		if(dt < 0) return;
		this.schedule(this.UpdateFBO, this.autoUpdateDt);
	}

	protected onDestroy(): void {
		if(this.spriteFBO && this.spriteFBO.isValid){
			this.spriteFBO.node.destroy()
			this.spriteFBO.spriteFrame && this.spriteFBO.spriteFrame.destroy()
		}
		if(this.renderTexture && this.renderTexture.isValid){
			this.renderTexture.destroy()
		}
		this.node && (this.node['__isNodeFBO'] = null)
	}

	/**
	 * 活动相机
	 */
    public RefreshCamera(){
		this.camera = this.FindCamera(this.node.group);
		if (!this.camera){
			console.error("NodeFBO,当前场景不存在相机:", this.parentGroup, this.getPath())
			return cc.Camera.main;
		}
        return this.camera;
    }

	public FindCamera(group: string) {
		let index = cc.game['groupList'].findIndex((v)=> v == group);
		if (index == null){
			console.error("NodeFBO,当前项目未设置分组:", group, this.getPath())
			return;
		}
		return cc.Camera.cameras.find((v)=> v.cullingMask & (1 << index));
	}

	public FindGroupIndex(group: string) {
		return cc.game['groupList'].findIndex((v: string)=> v == group);
	}

	/**
	 * 刷新帧缓存
	 * @param waitFps 等待帧数, 0:本帧刷新, 1:下一帧刷新, 2:下下帧刷新, 以此类推
	 */
	public UpdateFBO(waitFps: number = 0): void {
		if(waitFps <= this._waitFps || !this.isValid || !this.enabled) return;
		this._waitFps = waitFps;
		this.isStartUpdate = true;
	}

    private UpdataRenderTexture(rect: cc.Rect){
        if(!this.renderTexture){
            // this.renderTexture.destroy();
            this.renderTexture = new cc.RenderTexture();
            this.spriteFBO.spriteFrame.setTexture(this.renderTexture);
            this.renderTexture.name = this.spriteFBO.node.name;
        }
        
        this.renderTexture.initWithSize(rect.width, rect.height, cc.game['_renderContext'].STENCIL_INDEX8);
        this.spriteFBO.node.setContentSize(rect.width, rect.height);
        return this.renderTexture;
    }

	
	/** 快照帧2: 渲染 */ 
	private OnBeforeRenderScene(): void {
        // 开始前的准备
        // console.time("UpdateFBO start")
        // this.OnBeforeRenderFBO();
        let dt = SpineFboManager.GetSpineTime(this.spine) || 0;
        let fps = Math.floor(dt * 30);
        if(this.rect && this.animName == this.spine.animation && this.fps == fps){
            return;
        }
 
        this.fps = fps;
        this.animName = this.spine.animation;
        let rect = this.rect = SpineFboManager.GetSpineWorldRect(this.spine, dt, fps);
        // 开始渲染
        let renderTexture = this.UpdataRenderTexture(rect);
        this.node.convertToWorldSpaceAR(cc.v2(rect.x, rect.y), this._worldPos);
        this.camera.node.parent.convertToNodeSpaceAR(this._worldPos, this._worldPos);

        let old_renderTexture = this.camera.targetTexture;
        let old_clearFlags = this.camera.clearFlags;
        let old_bgColor = this.camera.backgroundColor;
        let old_x = this.camera.node.x;
        let old_y = this.camera.node.y;
        this.camera.targetTexture = renderTexture;
        this.camera.clearFlags = cc.Camera.ClearFlags.COLOR | cc.Camera.ClearFlags.DEPTH | cc.Camera.ClearFlags.STENCIL;
        this.camera.backgroundColor = cc.Color.TRANSPARENT;
        this.camera.zoomRatio = cc.winSize.height / rect.height;
        this.camera.node.x = this._worldPos.x + rect.width*0.5;
        this.camera.node.y = this._worldPos.y + rect.height*0.5;
        this.camera.render(this.node);
        this.camera.zoomRatio = 1;
        this.camera.node.x = old_x;
        this.camera.node.y = old_y;
        this.camera.clearFlags = old_clearFlags;
        this.camera.backgroundColor = old_bgColor;
        this.camera.targetTexture = old_renderTexture;

        // console.timeEnd("UpdateFBO start")
	}

	
	/**
	 * 刷新显示快照Node的位置
	 */
	public UpdateNodeFBOTransform(): void {
        this.spriteFBO.node.x = this.node.x + this.rect.x + this.rect.width * 0.5;
        this.spriteFBO.node.y = this.node.y + this.rect.y + this.rect.height * 0.5;
		// this.spriteFBO.node.setPosition(this.node.position);
	}

	public getPath() {
		let node = this.node;
        let path = node.name;
        let parent = node.parent;
        while (parent) {
            path = parent.name + "/" + path;
            parent = parent.parent;
        }
        return path;
    }
    // update (dt) {}
}
