export enum VideoAdTarget {
    Null = 0,
    /** 复活 */
    Revive,
}

export enum VideoResult {
    NoAd = -1,
    Fail = 0,
    Success,
}

export interface IPostVideoRecode {
    ad_log_id: number;
}

export interface IVideoData {
    /** 视频目的 */
    target: VideoAdTarget;
    /** 播放时间 */
    startTime: number;
    /** 结束时间 */
    endTime: number;
    /** 视频结果 */
    result: VideoResult;
    /** 记录ID */
    ad_log_id: number;

    postError: any;
}

export enum AdSetTakeType {
    Null = 0,
    VideoAd,
    Share,
}

export interface IPostVideoJson {
    id: number;
    /** 编号*/
    serial_no: string;
    /** 对应系统 0=资源获取 1=免费商品 */
    map_sys: number;
    /** 广告枚举 */
    ad_type: VideoAdTarget;
    /** 获取奖励 id=数量 之后不知道会用什么符号隔开 */
    reward: string;
    /** 上限 */
    take_limit: number;
    /** 灰钻开通后 上限 */
    grey_drill_take_limit: number;
    /** 广告间隔 */
    watch_interval: number;
    /** 0直接获取 1广告 2分享*/
    take_type: AdSetTakeType;
    /** 需要看几次广告 */
    need_watch_count: number;
    /** 分享所需次数 */
    need_share_count: number;
    /** 排序 */
    sort: number;
    /**  */
    share_type: number;
}

export interface IPostVideoStatue {
    count: number;
    watch_last_time: number;
}

export interface IPostVideoAdJson {
    id: string;
    ad_type: VideoAdTarget;
    title: string;
}