export default class GameData {

    //人与场景高度比例
    public static readonly ActorSceneScale: number = 3.25;
    //Spine角色高
    public static readonly ActorHeight = 260;
    //Spine角色宽
    public static readonly ActorWidth = 110;
    //Spine角色厚度
    public static readonly ActorThickness = 30;
    //游戏一屏数据
    public static get GameNodeWidth() { return this.gameNode.width};
    public static get GameNodeHeight() { return /*this.gameNode.height*/877};
    public static get GameSceneHeight() { return this.gameNode.height};
    public static get GameNodeScale() { return this.gameNode.scale};
    public static get GameNodeX() { return this.gameNode.scaleX};
    public static get GameNodeY() { return this.gameNode.scaleY};
    public static GameNodeYOffset: number = 0;
    // 当前场景Canvas根节点,注意锚点是 0.5,0.5
    public static get gameNode(): cc.Node{
        return cc.Canvas.instance.node;
    };

    /** 场景node */
    public static scene_node : cc.Node;

    public static CurGM: BasicGameManger;

    
    /** 转跳到关卡 */
    static gotoLevel(level: number, gameMode?: GameMode, callback?: ()=>any){
        if(GameData.CurGM){
            GameData.CurGM.EndGame();
            GameData.CurGM = null;
        }

        gameMode = gameMode || UserDataMgr.instance.GetSelectedGameMode();
        let gm: BasicGameManger;
        switch(gameMode){
            case GameMode.NDRG:
                gm = new NdrgGameManger();
                break;
            case GameMode.ZBT:
                gm = new ZbtGameManger();
                break;
            case GameMode.JQPT:
                gm = new JqptGameManger();
                break;
            case GameMode.KPQQ:
                gm = new KpqqGameManger();
                break;
        }
        if(gm){
            gm.createGame(level, callback);
            GameData.CurGM = gm;
        }
    }
}

CC_DEBUG && (window['GameData'] = GameData);