
type TimerEvent = { method:Function, caller:any, delay:number, repeat:boolean, delayTime:number , args:any[]}
/** 定时器工具 */
export class GameTimer {

    private timer_events: Map<string,TimerEvent[]> = new Map<string,TimerEvent[]>();
    protected scale: number = 1;

    /**
     * 定时重复执行。
     * @param delay 间隔时间(单位毫秒)。
     * @param caller 执行域(this)。
     * @param method 定时器回调函数。
     * @param args 回调参数。
     */
    public Loop(delay: number, caller: any, method: Function, group: string = 'default', args?: any[]): void {
        this.timer_events.has(group) || this.timer_events.set(group, []);
        this.timer_events.get(group).push({ method:method, caller:caller, delay:delay, repeat:true, delayTime:delay, args:args});
    }


    /**
     * 定时执行一次。
     * @param delay 延迟时间(单位为毫秒)。
     * @param caller 执行域(this)。
     * @param method 定时器回调函数。
     * @param args 回调参数。
     */
    public Once(delay: number, caller: any, method: Function, group: string = 'default', args?: any[]): void {
        this.timer_events.has(group) || this.timer_events.set(group, []);
        this.timer_events.get(group).push({ method:method, caller:caller, delay:delay, repeat:false, delayTime:delay, args:args});
    }

    /**
     * 更新定时器
     * @param delta 单位毫秒
     */
    public Update(delta: number) {
        for (const iterator of this.timer_events) {
            const timerLs = iterator[1];
            
            for (let i = 0; i < timerLs.length; i++) {
                const event = timerLs[i];
                event.delayTime -= delta * this.scale;
                if(event.delayTime <= 0){
                    if(event.repeat){
                        event.delayTime = event.delay;
                    }else{
                        // 一次性定时器
                        this.DelArrayByIdx(timerLs, i);
                        i--;
                    }
                    event.method.apply(event.caller, event.args);
                }
            }
        }
    }

    private DelArrayByIdx(arr: any[], idx: number) {
        for(let i = idx; i < arr.length - 1; i++){
            arr[i] = arr[i + 1];
        }
        if(arr.length){
            arr.length -= 1;
        }
    }


    /**
     * 通过分组清除定时器
     * @param group 
     */
    public ClearByGroup(group: string) {
        this.timer_events.delete(group);
    }

    public ClearAll() {
        this.timer_events.clear();
    }

    /**
     * 通过作用域清除定时器
     * @param caller 
     */
    public ClearByCaller(caller: any) {
        this.timer_events.forEach((value, key) => {
            let v = value.find((event) => {
                return event.caller == caller;
            }) 
            if(v){
                this.timer_events.set(key, value.filter((event) => {
                    return event.caller != caller;
                }));
            }
        });
    }
    
    public Clear(caller: any, method: Function) {
        this.timer_events.forEach((value, key) => {
            let v = value.find((event) => {
                return event.caller == caller && event.method == method;
            }) 
            if(v){
                this.timer_events.set(key, value.filter((event) => {
                    return event.caller == caller && event.method == method;
                }));
            }
        });
    }



}
