
import { GameEvent } from "../../System/GameEvent/GameEvent";
import { UserDataMgr } from "../../System/User/UserDataMgr";
import VideoAdSystem from "../../System/VideoAd/VideoAdManager";
import ViewBase from "../../engine/ViewBase";
import Singleton from "../../singleton/Singleton";
import { GameMode } from "../../gamePlaySystem/GameAttribute";

const {ccclass, property} = cc._decorator;

@ccclass
export default class UnlockView extends ViewBase {

	@property({ type: cc.Label, displayName:'' })
	adCount: cc.Label = null;

	@property({ type: cc.Node, displayName:'' })
	closeBtn: cc.Node = null;

	@property({ type: cc.Sprite, displayName:'' })
	unlookLvBtn: cc.Sprite = null;

	@property({ type: cc.Sprite, displayName:'' })
	seeAdBtn: cc.Sprite = null;

	private level: number;
	private gameMode: GameMode;

    start () {
		
		this.onAddEvent(this.closeBtn,()=>{
			this.closeView();
		})

		this.onAddEvent(this.unlookLvBtn.node,async ()=>{
			let scucess = await VideoAdSystem.PlayerVideoAd();
			if(!scucess) return;
			
			UserDataMgr.instance.SaveLevelLock(this.level, true, true, this.gameMode);
			this.isValid && this.closeView();
		})
		
		this.onAddEvent(this.seeAdBtn.node,async ()=>{
			let scucess = await VideoAdSystem.PlayerVideoAd();
			if(!scucess) return;

			UserDataMgr.instance.AddAdKeyCount();
			let count = UserDataMgr.instance.GetAdKeyCount();
			this.adCount.string = `${count}/3`;
			if(UserDataMgr.instance.GetUnlockTime()){
				this.closeView();
			}
		})
    }

	onDisable(): void {
		Singleton.GameEventSystem.dispatch(GameEvent.UP_HOME_UI);
	}
	
	onInitChild(level: number, gameMode?: GameMode){
		this.level = level;
		this.gameMode = gameMode || UserDataMgr.instance.GetSelectedGameMode() || GameMode.NDRG;
		
	}

}
