import DateUtil from "./DateUtil";
import { EngineConfig } from "./EngineConfig";
import VersionManager from "./VersionManager";

export default class ManifestConfig {

    public static packageUrl: string = "";
    public static remoteManifestUrl: string = "";
    public static remoteVersionUrl: string = "";
    // public static version: string = "1.0.0.0"; //更新包要更新这里  从左往右第二位是Ios大包版本号，第三位是android大包版本号
    public static assets: object = {};
    public static searchPaths: Array<any> = [];

    public static getManifestStr(key: string, hotupdateIndex: number) {
        let obj: Object = {};
        obj["packageUrl"] = EngineConfig.getHotUpdateUrl() + "/hotupdate/" + key + "/";
        obj["remoteManifestUrl"] = EngineConfig.getHotUpdateUrl() + "/hotupdate/" + key + "/project.manifest?t=" + DateUtil.now();
        obj["remoteVersionUrl"] = EngineConfig.getHotUpdateUrl() + "/hotupdate/" + key + "/version.manifest?t=" + DateUtil.now();
        obj["version"] = VersionManager.Version_List[hotupdateIndex];
        obj["assets"] = {
        };
        obj["searchPaths"] = [];
        return JSON.stringify(obj);
    }

}
