export class UI_Config {
    public path: string;    //路径
    public cacheType: UI_Cache_Type; //缓存类型
    public isSingle: boolean; //是否单例
    public bundleName:string; //所在bundle名字

    
    /**
     * 构造函数
     *
     * @param path 缓存路径
     * @param cacheType 缓存类型
     * @param isSingle 是否为单例
     * @param bundleName 缓存所属的Bundle名称
     */
    constructor(path: string, cacheType: UI_Cache_Type, isSingle: boolean,bundleName:string) {
        this.path = path;
        this.cacheType = cacheType;
        this.isSingle = isSingle;
        this.bundleName = bundleName;
    }
}


export enum UI_Cache_Type {
    always, //一直存在
    someTimes, //存在一会
    noCache, //不缓存
}

