// import Wx_StorageAPI from "../../../wx_api/Wx_StorageAPI";

import { EventManager } from "../../engine/EventManager";

// 持久化数据接口
export interface IStorageControler {
    Save(_force?: boolean);
    Load(value: any);
    Monitor: boolean;
} 

/**
 * 持久化数据管理类
 */
export default class StorageSystem extends EventManager {

    private static ss: StorageSystem = null;
    public static get Init(): StorageSystem {
        if (StorageSystem.ss == null) {
            StorageSystem.ss = new StorageSystem();
        }
        return StorageSystem.ss;
    }

    public static readonly EVENT_SAVE_BEGIN: string = "event_save_begin";
    public static readonly EVENT_LOAD_BEGIN: string = "event_load_begin";
    public static readonly EVENT_SAVE_SUCC: string = "event_save_succ";
    public static readonly EVENT_LOAD_SUCC: string = "event_load_succ";

    private data: Map<string, IStorageControler>;
    private SaveFunc: Function;
    private LoadFunc: Function;

    private constructor() {
        super();
        this.data = new Map<string, IStorageControler>();
        this.SaveFunc = this.SaveForLocal;
        this.LoadFunc = this.LoadForLocal;
    }

    public AddData(key: string, _data: IStorageControler) {
        this.data.set(key, _data);
    }

    /**保存所有已经添加的数据 */
    public Save() {
        let _data: any;
        let _has_change = false;
        const _savedata: any = {};
        this.event(StorageSystem.EVENT_SAVE_BEGIN);
        for (const key of this.data.keys()) {
            _data = this.data.get(key).Save();
            if (_data == null) continue;
            // Debug.log(0 , key + "   " + _data);
            _has_change = true;
            _savedata[key] = _data;
            this.SaveFunc(key, _data);
        }
        if (_has_change)
            this.event(StorageSystem.EVENT_SAVE_SUCC, _savedata);
    }

    /**读取 */
    public Load() {
        this.event(StorageSystem.EVENT_LOAD_BEGIN);
        for (const key of this.data.keys()) {
            // Debug.log(0 , key+"   "+this.LoadFunc(key)); 
            this.data.get(key).Load(this.LoadFunc(key));
        }
        this.event(StorageSystem.EVENT_LOAD_SUCC);
    }

    /** 保存记录转json */
    public DataToJson(): any {
        const _object: any = {};
        for (const key of this.data.keys()) {
            _object[key.toString()] = this.data.get(key).Save(true);
        }
        return _object;
    }

    /** json转保存记录 */
    public JsonToData(_value: any) {
        for (let key in _value) {
            if (this.data.has(key)) {
                this.data.get(key).Load(_value[key]);
            }
        }
    }

    /** 获取监视类 */
    public GetMonitorData() {
        const _object: any = {};
        for (const key of this.data.keys()) {
            if (this.data.get(key).Monitor) {
                _object[key.toString()] = this.data.get(key).Save();
            }
        }
        return JSON.stringify(_object);
    }

    public CleanData() {
        localStorage.clear();
    }

    // ---------------------↓保存方法,只要按照下面的方法逻辑写好，在构造的时候----------------------------
    // ---------------------赋值给SaveFunc，LoadFunc就可以实现不同的保存方案↓----------------------------

    /**
     * 保存微信
     */
    private SaveForWX(key: string, value: any) {
        // Wx_StorageAPI.Init.SetLocalStorage(key, value);
    }

    /**
     * 读取微信
     * @param key key值
     */
    private LoadForWx(key: string): any {
        // return Wx_StorageAPI.Init.GetLocalStorage(key);
        return null;
    }

    /**
     * 保存本地
     * @param key 
     * @param value 
     */
    private SaveForLocal(key: string, value) {
        cc.sys.localStorage.setItem(key, value);
    }

    /**
     * 读取本地
     * @param key
     */
    private LoadForLocal(key: string): any {
        return cc.sys.localStorage.getItem(key);
    }

    //外部调用
    public LoadToLocal(key: string):any{
        return this.LoadForLocal(key);
    }

    //外部调用
    public SaveToLocal(key: string,vale){
        this.SaveForLocal(key,vale);
    }
}