import Timer from "../../Tools/Timer";
import { Debug } from "../../engine/Logger";
import FGUIManager from "./FGUIManager";
import FguiButton from "./FguiButtom";
import { FguiButton2 } from "./FguiButton2";

export default abstract class BaseUIComponent {

    protected component: fairygui.GComponent;
    private _btnComArr: FguiButton2[];
    public get Com(): fairygui.GComponent {
        return this.component;
    }

    /** UI是否有效 */
    public get IsVaild(){
        return this.component && this.component.node && this.component.node["$gobj"] && this.component.node.isValid; 
    }

    public constructor(_component: fairygui.GComponent, ...args: any) {
        if(!_component) return; 
        this.component = _component;
        this.component.node.name += ':'+this.constructor.name;
        this.component.node['_fgui'] = this;
        FGUIManager.FindAndSetFGUILabelColor(this.component);
        this.Init(args);
        // Debug.warn("")
    }

    protected abstract Init(args: any);

    public UIBtn(name: string, getCom: fgui.GComponent, clickFunc: (com: FguiButton, ...args) => void, ...args):FguiButton2 {
        var btnCom = new FguiButton2(name, getCom, clickFunc, this, ...args);
        if (this._btnComArr == undefined) this._btnComArr = [];
        this._btnComArr.push(btnCom);
        return btnCom;
    }

    protected ClearBtnEvents() {
        if (this._btnComArr) {
            for (let i = 0, len = this._btnComArr.length; i < len; i++) {
                this._btnComArr[i].Dispose();
            }
            this._btnComArr.length = 0;
        }
    }

    /**外部调用刷新数据 */
    public ReflashView() { }

    /**移除 
     * fgui 组件引用置空
    */
    public Dispose() { 
        //fgui 组件引用置空 
        // this.component = null;
        this.ClearBtnEvents();
        Timer.clearAll(this);
    }
}