import BoolStorageValue from "../Storage/BoolStorageValue";
import ClassStorageValue from "../Storage/ClassStorageValue";
import NumberStorageValue from "../Storage/NumberStorageValue";
import StorageSystem from "../Storage/StorageSystem";
import StringStorageValue from "../Storage/StringStorageValue";
import Singleton from "../../singleton/Singleton";
import BaseGameSystem from "../BaseGameSystem";
import {GameEvent} from "../GameEvent/GameEvent";


export class SettingManager extends BaseGameSystem {

    loadingtips: { id: number, title: string, weight: number }[];

    constructor() {
        super();
        this._sceneSock = new BoolStorageValue("SceneSock", false);
    }

    private _vibrate: NumberStorageValue;// = 1;
    get Vibrate() { return this._vibrate.GetValue }
    /** 手机震动 */
    ChangeVibrate(on: boolean = null) {
        if (on == null) {
            this._vibrate.SetValue = (this._vibrate.GetValue + 1) % 2;
        } else {
            this._vibrate.SetValue = on ? 1 : 0;
        }
        Singleton.GameEventSystem.event(GameEvent.GamseSetChange);
        StorageSystem.Init.Save();
    }

    private _sceneSock: BoolStorageValue;
    get SceneSock(): boolean { return this._sceneSock.GetValue }
    /** 屏幕震动 */
    ChangeSceneSock(on: boolean = null) {
        if (on == null) {
            this._sceneSock.SetValue = !this._sceneSock.GetValue;
        } else {
            this._sceneSock.SetValue = on;
        }
        Singleton.GameEventSystem.event(GameEvent.GamseSetChange);
        StorageSystem.Init.Save();
    }

}
const SettingSystem = new SettingManager();
export default SettingSystem;
